import{_ as i,f as l,o as r,an as o}from"./chunks/framework.CFMQV-X7.js";const y=JSON.parse('{"title":"Maxfiylik siyosati","description":"","frontmatter":{},"headers":[],"relativePath":"uz_UZ/prologue/privacy.md","filePath":"uz_UZ/prologue/privacy.md","lastUpdated":1775810570000}'),s={name:"uz_UZ/prologue/privacy.md"};function n(h,a,t,m,e,u){return r(),l("div",null,a[0]||(a[0]=[o('<h1 id="maxfiylik-siyosati" tabindex="-1">Maxfiylik siyosati <a class="header-anchor" href="#maxfiylik-siyosati" aria-label="Permalink to “Maxfiylik siyosati”">​</a></h1><h2 id="ma-lumot-to-plash" tabindex="-1">Ma&#39;lumot to&#39;plash <a class="header-anchor" href="#ma-lumot-to-plash" aria-label="Permalink to “Ma&#39;lumot to&#39;plash”">​</a></h2><p>Siz goravel.dev saytiga tashrif buyurganingizda, biz siz haqingizda ma&#39;lum ma&#39;lumotlarni to&#39;playmiz. Bu ma&#39;lumotlarga quyidagilar kiradi:</p><ul><li>Veb-saytimizda tashrif buyurgan sahifalaringiz haqida ma&#39;lumot</li><li>Ixtiyoriy ravishda taqdim etgan boshqa har qanday ma&#39;lumot</li></ul><h2 id="ma-lumotlardan-foydalanish" tabindex="-1">Ma&#39;lumotlardan foydalanish <a class="header-anchor" href="#ma-lumotlardan-foydalanish" aria-label="Permalink to “Ma&#39;lumotlardan foydalanish”">​</a></h2><p>To&#39;plangan ma&#39;lumotlarni turli maqsadlarda, jumladan, quyidagilar uchun ishlatishimiz mumkin:</p><ul><li>Veb-saytimizdagi tajribangizni shaxsiylashtirish</li><li>Veb-saytimiz va xizmatlarimizni takomillashtirish</li><li>So&#39;rovingiz yoki iltimoslaringiz bo&#39;yicha siz bilan bog&#39;lanish</li></ul><h2 id="ma-lumotlar-xavfsizligi" tabindex="-1">Ma&#39;lumotlar xavfsizligi <a class="header-anchor" href="#ma-lumotlar-xavfsizligi" aria-label="Permalink to “Ma&#39;lumotlar xavfsizligi”">​</a></h2><p>Biz ma&#39;lumotlaringiz xavfsizligini jiddiy qabul qilamiz. Ma&#39;lumotlaringizni ruxsatsiz kirish, oshkor qilish, o&#39;zgartirish yoki yo&#39;q qilishdan himoya qilish uchun tegishli texnik va tashkiliy choralarni amalga oshiramiz.</p><h2 id="uchinchi-tomonlarga-oshkor-qilish" tabindex="-1">Uchinchi tomonlarga oshkor qilish <a class="header-anchor" href="#uchinchi-tomonlarga-oshkor-qilish" aria-label="Permalink to “Uchinchi tomonlarga oshkor qilish”">​</a></h2><p>Biz ma&#39;lumotlaringizni veb-saytimizni boshqarishda yoki sizga xizmat ko&#39;rsatishda bizga yordam beradigan ishonchli uchinchi tomonlar bilan baham ko&#39;rishimiz mumkin. Ushbu uchinchi tomonlar ma&#39;lumotlaringizni maxfiy va xavfsiz saqlash majburiyatini shartnoma asosida olgan.</p><h2 id="cookie-fayllar" tabindex="-1">Cookie-fayllar <a class="header-anchor" href="#cookie-fayllar" aria-label="Permalink to “Cookie-fayllar”">​</a></h2><p>Veb-saytimiz sizning ko&#39;rish tajribangizni yaxshilash uchun cookies-lardan foydalanishi mumkin. Cookies - bu qurilmangizda saqlanadigan va ma&#39;lum funksiyalar va imkoniyatlarni ta&#39;minlaydigan kichik fayllardir. Siz brauzer sozlamalaringizda cookies-larni o&#39;chirib qo&#39;yishni tanlashingiz mumkin, ammo e&#39;tibor bering, veb-saytimizning ba&#39;zi qismlari to&#39;g&#39;ri ishlamasligi mumkin.</p><h2 id="ushbu-siyosatga-o-zgartirishlar" tabindex="-1">Ushbu siyosatga o&#39;zgartirishlar <a class="header-anchor" href="#ushbu-siyosatga-o-zgartirishlar" aria-label="Permalink to “Ushbu siyosatga o&#39;zgartirishlar”">​</a></h2><p>Biz ushbu Maxfiylik siyosatini vaqti-vaqti bilan yangilashimiz mumkin. Har qanday o&#39;zgartirishlar ushbu sahifada joylashtiriladi va qayta ko&#39;rib chiqilgan siyosat joylashtirilgandan so&#39;ng darhol kuchga kiradi.</p>',15)]))}const g=i(s,[["render",n]]);export{y as __pageData,g as default};
